sys_script_include.script:
var AN_ACLScanner = Class.create();
AN_ACLScanner.prototype = {

    scan: function(scanId) {

        var scanGR = new GlideRecord('x_1920012_apprai_0_an_scan');

        if (!scanGR.get(scanId))
            return;

        var scopeName = scanGR.app_scope.toString();

        var totalTables = 0;
        var protectedTables = 0;

        var tableGR = new GlideRecord('sys_db_object');
        tableGR.addQuery('name', 'STARTSWITH', scopeName);
        tableGR.query();

        while (tableGR.next()) {

            totalTables++;

            var tableName = tableGR.name.toString();

            var aclGR = new GlideRecord('sys_security_acl');
            aclGR.addQuery('name', tableName);
            aclGR.query();

            if (aclGR.hasNext()) {

                protectedTables++;

            } else {

                var finding = new GlideRecord('x_1920012_apprai_0_an_finding');

                finding.initialize();
                finding.scan = scanId;
                finding.dimension = 'security';
                finding.severity = 'critical';
                finding.title = 'Missing ACL';
                finding.description =
                    'Table ' + tableName +
                    ' has no ACL protection.';
                finding.insert();
            }
        }

        var score = 100;

        if (totalTables > 0)
            score = Math.round((protectedTables / totalTables) * 100);

        var scorecard = new GlideRecord('x_1920012_apprai_0_an_scorecard');

        scorecard.addQuery('scan', scanId);
        scorecard.query();

        if (!scorecard.next()) {
            scorecard.initialize();
            scorecard.scan = scanId;
            scorecard.insert();
            scorecard.get(scorecard.sys_id);
        }

        scorecard.security_score = score;
        scorecard.update();
    },

    type: 'AN_ACLScanner'
};
